SwiftPython <pre><code>import ApplePy
@preconcurrency import ApplePyFFI

@PyFunction
func greet(name: String, greeting: String = "Hello") -&gt; String {
    "\(greeting), \(name)! 🍎"
}

@PyModule("mylib", functions: [greet])
func mylib() {}
</code></pre> <pre><code>&gt;&gt;&gt; import mylib
&gt;&gt;&gt; mylib.greet("World")
'Hello, World! 🍎'
&gt;&gt;&gt; mylib.greet("World", "Hi")
'Hi, World! 🍎'
</code></pre>

ApplePy (Swift)PyO3 (Rust) <pre><code>import ApplePy
@preconcurrency import ApplePyFFI

@PyFunction
func add(a: Int, b: Int) -&gt; Int {
    a + b
}

@PyModule("mylib", functions: [add])
func mylib() {}
</code></pre> <pre><code>use pyo3::prelude::*;

#[pyfunction]
fn add(a: i64, b: i64) -&gt; i64 {
    a + b
}

#[pymodule]
fn mylib(m: &amp;Bound&lt;'_, PyModule&gt;) -&gt; PyResult&lt;()&gt; {
    m.add_function(wrap_pyfunction!(add, m)?)?;
    Ok(())
}
</code></pre>
